          <el-table-column prop="kefangtupian" header-align="center" align="center" label="????" width="120">
            <template slot-scope="scope">
              <div v-if="scope.row.kefangtupian">
                <img :src="scope.row.kefangtupian.split(',')[0]" width="80" height="60" style="object-fit: cover;">
              </div>
              <div v-else>???</div>
            </template>
          </el-table-column>
          <el-table-column prop="fangjianmianji" header-align="center" align="center" label="????"></el-table-column>
          <el-table-column prop="jiage" header-align="center" align="center" label="??">
            <template slot-scope="scope">
              <span style="color: #f56c6c;">�{{ scope.row.jiage }}</span>
            </template>
          </el-table-column>
          <el-table-column prop="kefangzhuangtai" header-align="center" align="center" label="????">
            <template slot-scope="scope">
              <el-tag :type="scope.row.kefangzhuangtai == '??' ? 'success' : 'danger'">{{ scope.row.kefangzhuangtai }}</el-tag>
            </template>
          </el-table-column>
          <el-table-column prop="keyueshijian" header-align="center" align="center" label="????" width="160"></el-table-column>
          <el-table-column prop="weishengqingkuang" header-align="center" align="center" label="????"></el-table-column>
          <el-table-column prop="kefanghuanjing" header-align="center" align="center" label="????" show-overflow-tooltip></el-table-column>
          <el-table-column prop="suoshujiudian" header-align="center" align="center" label="????"></el-table-column>
          <el-table-column header-align="center" align="center" label="??" width="320">
            <template slot-scope="scope">
              <el-button v-if="isAuth('kefangxinxi','??')" type="success" icon="el-icon-tickets" size="mini" @click="addOrUpdateHandler(scope.row.id,'info')">??</el-button>
              <el-button v-if="isAuth('kefangxinxi','????')" type="warning" icon="el-icon-date" size="mini" @click="yonghuyuyueCrossAddOrUpdateHandler(scope.row,'cross')">????</el-button>
              <el-button v-if="isAuth('kefangxinxi','????')" type="warning" icon="el-icon-date" size="mini" @click="huiyuanyuyueCrossAddOrUpdateHandler(scope.row,'cross')">????</el-button>
              <el-button v-if="isAuth('kefangxinxi','??')" type="primary" icon="el-icon-edit" size="mini" @click="addOrUpdateHandler(scope.row.id)">??</el-button>
              <el-button v-if="isAuth('kefangxinxi','??')" type="danger" icon="el-icon-delete" size="mini" @click="deleteHandler(scope.row.id)">??</el-button>
            </template>
