        <el-pagination :layout="'total, sizes, prev, pager, next, jumper'" @size-change="sizeChangeHandle" @current-change="currentChangeHandle" :current-page="pageIndex" :page-sizes="[10, 20, 50, 100]" :page-size="pageSize" :total="totalPage" background style="text-align:right;margin-top:15px;"></el-pagination>
      </div>
    </div>
    <add-or-update v-if="addOrUpdateFlag" :parent="this" ref="addOrUpdate"></add-or-update>
    <yonghuyuyue-cross-add-or-update v-if="yonghuyuyueCrossAddOrUpdateFlag" :parent="this" ref="yonghuyuyueCrossaddOrUpdate"></yonghuyuyue-cross-add-or-update>
    <huiyuanyuyue-cross-add-or-update v-if="huiyuanyuyueCrossAddOrUpdateFlag" :parent="this" ref="huiyuanyuyueCrossaddOrUpdate"></huiyuanyuyue-cross-add-or-update>
  </div>
</template>
<script>
import AddOrUpdate from "./add-or-update";
import yonghuyuyueCrossAddOrUpdate from "../yonghuyuyue/add-or-update";
import huiyuanyuyueCrossAddOrUpdate from "../huiyuanyuyue/add-or-update";
export default {
  data() {
    return {
      searchForm: { kefanghao: "", chuangxing: "", kefangzhuangtai: "" },
      dataList: [],
      pageIndex: 1,
      pageSize: 10,
      totalPage: 0,
      dataListLoading: false,
      dataListSelections: [],
      showFlag: true,
      addOrUpdateFlag: false,
      yonghuyuyueCrossAddOrUpdateFlag: false,
      huiyuanyuyueCrossAddOrUpdateFlag: false,
      kefangzhuangtaiOptions: ['???', '??']
    };
  },
  created() {
    this.getDataList();
  },
  components: { AddOrUpdate, yonghuyuyueCrossAddOrUpdate, huiyuanyuyueCrossAddOrUpdate },
  methods: {
    search() {
      this.pageIndex = 1;
      this.getDataList();
    },
    getDataList() {
      this.dataListLoading = true;
      let params = { page: this.pageIndex, limit: this.pageSize, sort: 'id' };
      if (this.searchForm.kefanghao) params['kefanghao'] = '%' + this.searchForm.kefanghao + '%';
      if (this.searchForm.chuangxing) params['chuangxing'] = '%' + this.searchForm.chuangxing + '%';
      if (this.searchForm.kefangzhuangtai) params['kefangzhuangtai'] = this.searchForm.kefangzhuangtai;
      this.$http({ url: "kefangxinxi/page", method: "get", params: params }).then(({ data }) => {
        if (data && data.code === 0) {
          this.dataList = data.data.list;
          this.totalPage = data.data.total;
        } else {
          this.dataList = [];
          this.totalPage = 0;
        }
        this.dataListLoading = false;
      });
    },
    sizeChangeHandle(val) {
      this.pageSize = val;
      this.pageIndex = 1;
      this.getDataList();
    },
    currentChangeHandle(val) {
      this.pageIndex = val;
      this.getDataList();
    },
    selectionChangeHandler(val) {
      this.dataListSelections = val;
    },
    addOrUpdateHandler(id, type) {
      this.showFlag = false;
      this.addOrUpdateFlag = true;
      this.yonghuyuyueCrossAddOrUpdateFlag = false;
      this.huiyuanyuyueCrossAddOrUpdateFlag = false;
      this.$nextTick(() => {
        this.$refs.addOrUpdate.init(id, type || 'else');
      });
    },
    yonghuyuyueCrossAddOrUpdateHandler(row, type) {
      this.showFlag = false;
      this.addOrUpdateFlag = false;
      this.yonghuyuyueCrossAddOrUpdateFlag = true;
      this.huiyuanyuyueCrossAddOrUpdateFlag = false;
      this.$storage.set('crossObj', row);
      this.$storage.set('crossTable', 'kefangxinxi');
      this.$nextTick(() => {
        this.$refs.yonghuyuyueCrossaddOrUpdate.init(row.id, type);
      });
    },
    huiyuanyuyueCrossAddOrUpdateHandler(row, type) {
      this.showFlag = false;
      this.addOrUpdateFlag = false;
      this.yonghuyuyueCrossAddOrUpdateFlag = false;
      this.huiyuanyuyueCrossAddOrUpdateFlag = true;
      this.$storage.set('crossObj', row);
      this.$storage.set('crossTable', 'kefangxinxi');
      this.$nextTick(() => {
        this.$refs.huiyuanyuyueCrossaddOrUpdate.init(row.id, type);
      });
    },
    deleteHandler(id) {
      var ids = id ? [Number(id)] : this.dataListSelections.map(item => Number(item.id));
      this.$confirm(`????[${id ? "??" : "????"}]???`, "??", { confirmButtonText: "??", cancelButtonText: "??", type: "warning" }).then(() => {
        this.$http({ url: "kefangxinxi/delete", method: "post", data: ids }).then(({ data }) => {
          if (data && data.code === 0) {
            this.$message({ message: "????", type: "success", duration: 1500, onClose: () => { this.search(); } });
          } else {
            this.$message.error(data.msg);
          }
        });
      });
    }
  }
};
</script>
