<script>
import AddOrUpdate from "./add-or-update";
export default {
  data() {
    return {
      searchForm: { kefanghao: "", xingming: "" },
      dataList: [],
      pageIndex: 1,
      pageSize: 10,
      totalPage: 0,
      dataListLoading: false,
      dataListSelections: [],
      showFlag: true,
      addOrUpdateFlag: false,
      sfshVisiable: false,
      shForm: {}
    };
  },
  created() { this.getDataList(); },
  components: { AddOrUpdate },
  methods: {
    search() { this.pageIndex = 1; this.getDataList(); },
    getDataList() {
      this.dataListLoading = true;
      let params = { page: this.pageIndex, limit: this.pageSize, sort: 'id' };
      if (this.searchForm.kefanghao) params['kefanghao'] = '%' + this.searchForm.kefanghao + '%';
      if (this.searchForm.xingming) params['xingming'] = '%' + this.searchForm.xingming + '%';
      this.$http({ url: "yonghuquxiao/page", method: "get", params: params }).then(({ data }) => {
        if (data && data.code === 0) { this.dataList = data.data.list; this.totalPage = data.data.total; }
        else { this.dataList = []; this.totalPage = 0; }
        this.dataListLoading = false;
      });
    },
    sizeChangeHandle(val) { this.pageSize = val; this.pageIndex = 1; this.getDataList(); },
    currentChangeHandle(val) { this.pageIndex = val; this.getDataList(); },
    selectionChangeHandler(val) { this.dataListSelections = val; },
    addOrUpdateHandler(id, type) {
      this.showFlag = false;
      this.addOrUpdateFlag = true;
      this.$nextTick(() => { this.$refs.addOrUpdate.init(id, type || 'else'); });
    },
    payHandler(row) {
      this.$storage.set('paytable', 'yonghuquxiao');
      this.$storage.set('payObject', row);
      this.$router.push('pay');
    },
    shDialog(row) {
      this.sfshVisiable = !this.sfshVisiable;
      if (row) {
        this.shForm = {
          yuyuebianhao: row.yuyuebianhao, kefanghao: row.kefanghao, shifouquxiao: row.shifouquxiao,
          jiage: row.jiage, tianshu: row.tianshu, zongjia: row.zongjia, quxiaoyuanyin: row.quxiaoyuanyin,
          quxiaoshijian: row.quxiaoshijian, zhanghao: row.zhanghao, xingming: row.xingming,
          shouji: row.shouji, shenfenzheng: row.shenfenzheng, sfsh: row.sfsh, shhf: row.shhf, ispay: row.ispay, id: row.id
        };
      }
    },
    shHandler() {
      this.$confirm(`?????`, "??", { confirmButtonText: "??", cancelButtonText: "??", type: "warning" }).then(() => {
        this.$http({ url: "yonghuquxiao/update", method: "post", data: this.shForm }).then(({ data }) => {
          if (data && data.code === 0) { this.$message.success("????"); this.getDataList(); this.shDialog(); }
          else { this.$message.error(data.msg); }
        });
      });
    },
    deleteHandler(id) {
      var ids = id ? [Number(id)] : this.dataListSelections.map(item => Number(item.id));
      this.$confirm(`????[${id ? "??" : "????"}]???`, "??", { confirmButtonText: "??", cancelButtonText: "??", type: "warning" }).then(() => {
        this.$http({ url: "yonghuquxiao/delete", method: "post", data: ids }).then(({ data }) => {
          if (data && data.code === 0) { this.$message.success("????"); this.search(); }
          else { this.$message.error(data.msg); }
        });
      });
    }
  }
};
</script>
