        dasaoshijian: '',
        qingjiezhanghao: '',
        qingjiexingming: '',
      },
      shifoudasaoOptions: [],
      rules: {
          kefanghao: [
          ],
          kefangleixing: [
          ],
          suoshujiudian: [
          ],
          shifoudasao: [
          ],
          dasaoshijian: [
          ],
          qingjiezhanghao: [
          ],
          qingjiexingming: [
          ],
      }
    };
  },
  props: ["parent"],
  computed: {
  },
  created() {
    this.ruleForm.dasaoshijian = this.getCurDateTime()
    this.addEditStyleChange()
    this.addEditUploadStyleChange()
  },
  methods: {
    download(file){
      window.open(`${file}`)
    },
    getCurDateTime() {
      var now = new Date();
      var year = now.getFullYear();
      var month = (now.getMonth() + 1).toString().padStart(2, '0');
      var day = now.getDate().toString().padStart(2, '0');
      var hours = now.getHours().toString().padStart(2, '0');
      var minutes = now.getMinutes().toString().padStart(2, '0');
      var seconds = now.getSeconds().toString().padStart(2, '0');
      return year + '-' + month + '-' + day + ' ' + hours + ':' + minutes + ':' + seconds;
    },
    init(id,type) {
      if (id) {
        this.id = id;
        this.type = type;
      }
      if(this.type=='info'||this.type=='else'){
        this.info(id);
      }else if(this.type=='cross'){
        var obj = this.$storage.getObj('crossObj');
        for (var o in obj){
          if(o=='kefanghao'){
            this.ruleForm.kefanghao = obj[o];
            this.ro.kefanghao = true;
            continue;
          }
          if(o=='kefangleixing'){
            this.ruleForm.kefangleixing = obj[o];
            this.ro.kefangleixing = true;
            continue;
          }
          if(o=='suoshujiudian'){
            this.ruleForm.suoshujiudian = obj[o];
            this.ro.suoshujiudian = true;
            continue;
          }
          if(o=='shifoudasao'){
            this.ruleForm.shifoudasao = obj[o];
            this.ro.shifoudasao = true;
            continue;
          }
          if(o=='dasaoshijian'){
            this.ruleForm.dasaoshijian = obj[o];
            this.ro.dasaoshijian = true;
            continue;
          }
          if(o=='qingjiezhanghao'){
            this.ruleForm.qingjiezhanghao = obj[o];
            this.ro.qingjiezhanghao = true;
            continue;
          }
          if(o=='qingjiexingming'){
            this.ruleForm.qingjiexingming = obj[o];
            this.ro.qingjiexingming = true;
            continue;
          }
        }
        if(!this.ruleForm.shifoudasao || this.ruleForm.shifoudasao === ''){
          this.ruleForm.shifoudasao = '是';
        }
        if(!this.ruleForm.dasaoshijian || this.ruleForm.dasaoshijian === ''){
          this.ruleForm.dasaoshijian = this.getCurDateTime();
        }
      }
      this.$http({
        url: `${this.$storage.get('sessionTable')}/session`,
        method: "get"
      }).then(({ data }) => {
        if (data && data.code === 0) {
          var json = data.data;
          if(json.qingjiezhanghao!=''&&json.qingjiezhanghao){
            this.ruleForm.qingjiezhanghao = json.qingjiezhanghao
          }
          if(json.qingjiexingming!=''&&json.qingjiexingming){
            this.ruleForm.qingjiexingming = json.qingjiexingming
          }
        } else {
          this.$message.error(data.msg);
        }
      });
      this.shifoudasaoOptions = "是,否".split(',')
    },
    info(id) {
      this.$http({
        url: `qingsaofangjian/info/${id}`,
        method: "get"
      }).then(({ data }) => {
        if (data && data.code === 0) {
        this.ruleForm = data.data;
        let reg=new RegExp('../../../upload','g')
        } else {
          this.$message.error(data.msg);
        }
      });
    },
    onSubmit() {
      this.$refs["ruleForm"].validate(valid => {
        if (valid) {
          this.$http({
            url: `qingsaofangjian/${!this.ruleForm.id ? "save" : "update"}`,
            method: "post",
            data: this.ruleForm
          }).then(({ data }) => {
            if (data && data.code === 0) {
              this.$message({
                message: "操作成功",
                type: "success",
                duration: 1500,
                onClose: () => {
                  this.parent.showFlag = true;
                  this.parent.addOrUpdateFlag = false;
                  this.parent.qingsaofangjianCrossAddOrUpdateFlag = false;
                  this.parent.search();
                  this.parent.contentStyleChange();
                }
              });
            } else {
              this.$message.error(data.msg);
            }
          });
        }
      });
    },
    getUUID () {
      return new Date().getTime();
    },
    back() {
      this.parent.showFlag = true;
      this.parent.addOrUpdateFlag = false;
      this.parent.qingsaofangjianCrossAddOrUpdateFlag = false;
      this.parent.contentStyleChange();
    },
    addEditStyleChange() {
      this.$nextTick(()=>{
        document.querySelectorAll('.addEdit-block .input .el-input__inner').forEach(el=>{
          el.style.height = this.addEditForm.inputHeight
          el.style.color = this.addEditForm.inputFontColor
          el.style.fontSize = this.addEditForm.inputFontSize
          el.style.borderWidth = this.addEditForm.inputBorderWidth
          el.style.borderStyle = this.addEditForm.inputBorderStyle
          el.style.borderColor = this.addEditForm.inputBorderColor
          el.style.borderRadius = this.addEditForm.inputBorderRadius
          el.style.backgroundColor = this.addEditForm.inputBgColor
        })
        document.querySelectorAll('.addEdit-block .input .el-form-item__label').forEach(el=>{
          el.style.lineHeight = this.addEditForm.inputHeight
