<template>
  <div class="main-content">
    <div v-if="showFlag">
      <el-form :inline="true" :model="searchForm" class="form-content">
        <el-row :gutter="20" class="slt">
          <el-form-item label="????">
            <el-input prefix-icon="el-icon-search" v-model="searchForm.huiyuanzhanghao" placeholder="????" clearable></el-input>
          </el-form-item>
          <el-form-item label="????">
            <el-select v-model="searchForm.jifenleixing" placeholder="?????" clearable>
              <el-option v-for="item in typeOptions" :key="item" :label="item" :value="item"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item>
            <el-button icon="el-icon-search" type="success" @click="search()">??</el-button>
          </el-form-item>
        </el-row>
      </el-form>
      <div class="table-content">
        <el-table class="tables" size="medium" border stripe :data="dataList" v-loading="dataListLoading">
          <el-table-column label="??" type="index" width="60" align="center"></el-table-column>
          <el-table-column prop="huiyuanzhanghao" header-align="center" align="center" label="????"></el-table-column>
          <el-table-column prop="huiyuanxingming" header-align="center" align="center" label="????"></el-table-column>
          <el-table-column prop="jifenleixing" header-align="center" align="center" label="????">
            <template slot-scope="scope">
              <el-tag :type="getTypeTagType(scope.row.jifenleixing)">{{scope.row.jifenleixing}}</el-tag>
            </template>
          </el-table-column>
          <el-table-column prop="jifenshuliang" header-align="center" align="center" label="????">
            <template slot-scope="scope">
              <span :style="{color: scope.row.jifenshuliang > 0 ? '#67c23a' : '#f56c6c'}">
                {{scope.row.jifenshuliang > 0 ? '+' : ''}}{{scope.row.jifenshuliang}}
              </span>
            </template>
          </el-table-column>
          <el-table-column prop="beizhu" header-align="center" align="center" label="??" show-overflow-tooltip></el-table-column>
          <el-table-column prop="addtime" header-align="center" align="center" label="????" width="160"></el-table-column>
          <el-table-column header-align="center" align="center" label="??" width="150">
            <template slot-scope="scope">
              <el-button v-if="isAuth('jifen','??')" type="success" icon="el-icon-tickets" size="mini" @click="addOrUpdateHandler(scope.row.id,'info')">??</el-button>
              <el-button v-if="isAuth('jifen','??')" type="danger" icon="el-icon-delete" size="mini" @click="deleteHandler(scope.row.id)">??</el-button>
            </template>
          </el-table-column>
        </el-table>
        <el-pagination :layout="'total, sizes, prev, pager, next, jumper'" @size-change="sizeChangeHandle" @current-change="currentChangeHandle" :current-page="pageIndex" :page-sizes="[10, 20, 50, 100]" :page-size="pageSize" :total="totalPage" background style="text-align:right;margin-top:15px;"></el-pagination>
      </div>
    </div>
    <add-or-update v-if="addOrUpdateFlag" :parent="this" ref="addOrUpdate"></add-or-update>
  </div>
</template>
<script>
import AddOrUpdate from "./add-or-update";
export default {
  data() {
    return {
      searchForm: { huiyuanzhanghao: "", jifenleixing: "" },
      dataList: [],
      pageIndex: 1,
      pageSize: 10,
      totalPage: 0,
      dataListLoading: false,
      showFlag: true,
      addOrUpdateFlag: false,
      typeOptions: ['????', '????', '????', '????', '????', '????', '????']
    };
  },
  created() { this.getDataList(); },
  components: { AddOrUpdate },
  methods: {
    getTypeTagType(type) {
      const map = { '????': 'success', '????': 'primary', '????': 'warning', '????': 'info', '????': 'success', '????': 'danger', '????': 'info' };
      return map[type] || '';
    },
    search() { this.pageIndex = 1; this.getDataList(); },
    getDataList() {
      this.dataListLoading = true;
      let params = { page: this.pageIndex, limit: this.pageSize, sort: 'id' };
      if(this.searchForm.huiyuanzhanghao) params['huiyuanzhanghao'] = '%' + this.searchForm.huiyuanzhanghao + '%';
      if(this.searchForm.jifenleixing) params['jifenleixing'] = this.searchForm.jifenleixing;
      this.$http({ url: "jifen/page", method: "get", params: params }).then(({ data }) => {
        if (data && data.code === 0) { this.dataList = data.data.list; this.totalPage = data.data.total; }
        else { this.dataList = []; this.totalPage = 0; }
        this.dataListLoading = false;
      });
    },
    sizeChangeHandle(val) { this.pageSize = val; this.pageIndex = 1; this.getDataList(); },
    currentChangeHandle(val) { this.pageIndex = val; this.getDataList(); },
    addOrUpdateHandler(id, type) {
      this.showFlag = false;
      this.addOrUpdateFlag = true;
      this.$nextTick(() => { this.$refs.addOrUpdate.init(id, type || 'else'); });
    },
    deleteHandler(id) {
      this.$confirm('?????????', "??", { confirmButtonText: "??", cancelButtonText: "??", type: "warning" }).then(() => {
        this.$http({ url: "jifen/delete", method: "post", data: [Number(id)] }).then(({ data }) => {
          if (data && data.code === 0) { this.$message.success("????"); this.search(); }
          else { this.$message.error(data.msg); }
        });
      });
    }
  }
};
</script>
<style lang="scss" scoped>
.slt { margin: 0 !important; display: flex; }
.tables {
  &::v-deep .el-button--success { background-color: rgba(36, 194, 205, 1); border-color: rgba(36, 194, 205, 1); }
  &::v-deep .el-button { margin: 4px; }
}
</style>
