<template>
  <div class="main-content">
    <div v-if="showFlag">
      <el-form :inline="true" :model="searchForm" class="form-content">
        <el-row :gutter="20" class="slt" style="justify-content:flex-start">
          <el-form-item label="???">
            <el-input prefix-icon="el-icon-search" v-model="searchForm.kefanghao" placeholder="???" clearable></el-input>
          </el-form-item>
          <el-form-item label="????">
            <el-input prefix-icon="el-icon-search" v-model="searchForm.kefangleixing" placeholder="????" clearable></el-input>
          </el-form-item>
          <el-form-item>
            <el-button icon="el-icon-search" type="success" @click="search()">??</el-button>
            <el-button icon="el-icon-refresh" type="info" @click="resetSearch()">??</el-button>
          </el-form-item>
        </el-row>
        <el-row class="ad">
          <el-form-item>
            <el-tag type="warning" size="medium" style="margin-right:10px;">
              <i class="el-icon-warning"></i> ???????: {{ totalPage }}
            </el-tag>
          </el-form-item>
        </el-row>
      </el-form>
      <div class="table-content">
        <el-table class="tables" size="medium" show-header border fit stripe style="width:100%;font-size:14px" v-if="isAuth('daiqingsao','??')" :data="dataList" v-loading="dataListLoading">
          <el-table-column label="??" type="index" width="60" align="center"></el-table-column>
          <el-table-column sortable align="center" prop="kefanghao" header-align="center" label="???" width="120">
            <template slot-scope="scope">
              <el-tag type="primary">{{scope.row.kefanghao}}</el-tag>
            </template>
          </el-table-column>
          <el-table-column sortable align="center" prop="kefangleixing" header-align="center" label="????" width="120">
            <template slot-scope="scope">{{scope.row.kefangleixing}}</template>
          </el-table-column>
          <el-table-column sortable align="center" prop="louceng" header-align="center" label="??" width="80">
            <template slot-scope="scope">{{scope.row.louceng || '-'}}</template>
          </el-table-column>
          <el-table-column sortable align="center" prop="chuangxing" header-align="center" label="??" width="100">
            <template slot-scope="scope">{{scope.row.chuangxing}}</template>
          </el-table-column>
          <el-table-column sortable align="center" prop="suoshujiudian" header-align="center" label="????">
            <template slot-scope="scope">{{scope.row.suoshujiudian}}</template>
          </el-table-column>
          <el-table-column align="center" prop="kefangzhuangtai" header-align="center" label="????" width="100">
            <template slot-scope="scope">
              <el-tag :type="scope.row.kefangzhuangtai=='???'?'warning':'info'">{{scope.row.kefangzhuangtai}}</el-tag>
            </template>
          </el-table-column>
          <el-table-column align="center" prop="weishengqingkuang" header-align="center" label="????" width="100">
            <template slot-scope="scope">
              <el-tag :type="scope.row.weishengqingkuang=='???'?'danger':'success'">{{scope.row.weishengqingkuang}}</el-tag>
            </template>
          </el-table-column>
          <el-table-column width="200" align="center" header-align="center" label="??">
            <template slot-scope="scope">
              <el-button v-if="isAuth('daiqingsao','??')" type="info" icon="el-icon-view" size="mini" @click="viewDetail(scope.row)">??</el-button>
              <el-button v-if="isAuth('daiqingsao','??')" type="success" icon="el-icon-check" size="mini" @click="cleanRoom(scope.row)">??</el-button>
            </template>
          </el-table-column>
        </el-table>
        <el-pagination layout="total, sizes, prev, pager, next, jumper" @size-change="sizeChangeHandle" @current-change="currentChangeHandle" :current-page="pageIndex" :page-sizes="[10, 20, 50, 100]" :page-size="pageSize" :total="totalPage" class="pagination-content" background style="text-align:right;margin-top:15px;"></el-pagination>
      </div>
    </div>
    <el-dialog title="????" :visible.sync="detailVisible" width="600px">
      <el-descriptions :column="2" border v-if="currentRoom">
        <el-descriptions-item label="???">{{currentRoom.kefanghao}}</el-descriptions-item>
        <el-descriptions-item label="????">{{currentRoom.kefangleixing}}</el-descriptions-item>
        <el-descriptions-item label="??">{{currentRoom.chuangxing}}</el-descriptions-item>
        <el-descriptions-item label="??">{{currentRoom.louceng || '-'}}</el-descriptions-item>
        <el-descriptions-item label="????">{{currentRoom.fangjianmianji}}</el-descriptions-item>
        <el-descriptions-item label="??">{{currentRoom.jiage}}</el-descriptions-item>
        <el-descriptions-item label="????">
          <el-tag :type="currentRoom.kefangzhuangtai=='???'?'warning':'info'">{{currentRoom.kefangzhuangtai}}</el-tag>
        </el-descriptions-item>
        <el-descriptions-item label="????">
          <el-tag :type="currentRoom.weishengqingkuang=='???'?'danger':'success'">{{currentRoom.weishengqingkuang}}</el-tag>
        </el-descriptions-item>
        <el-descriptions-item label="????" :span="2">{{currentRoom.suoshujiudian}}</el-descriptions-item>
        <el-descriptions-item label="????" :span="2">{{currentRoom.kefanghuanjing || '-'}}</el-descriptions-item>
      </el-descriptions>
      <div slot="footer">
        <el-button @click="detailVisible = false">??</el-button>
        <el-button type="success" icon="el-icon-check" @click="cleanRoom(currentRoom)">????</el-button>
      </div>
    </el-dialog>
  </div>
</template>
<script>
export default {
  data() {
    return {
      searchForm: { kefanghao: "", kefangleixing: "" },
      dataList: [],
      pageIndex: 1,
      pageSize: 10,
      totalPage: 0,
      dataListLoading: false,
      showFlag: true,
      detailVisible: false,
      currentRoom: null
    };
  },
  created() { this.getDataList(); },
  methods: {
    search() { this.pageIndex = 1; this.getDataList(); },
    resetSearch() { this.searchForm = { kefanghao: "", kefangleixing: "" }; this.search(); },
    getDataList() {
      this.dataListLoading = true;
      let params = { page: this.pageIndex, limit: this.pageSize, sort: 'id' };
      if (this.searchForm.kefanghao) params['kefanghao'] = '%' + this.searchForm.kefanghao + '%';
      if (this.searchForm.kefangleixing) params['kefangleixing'] = '%' + this.searchForm.kefangleixing + '%';
      this.$http({ url: "daiqingsao/page", method: "get", params: params }).then(({ data }) => {
        if (data && data.code === 0) { this.dataList = data.data.list; this.totalPage = data.data.total; }
        else { this.dataList = []; this.totalPage = 0; }
        this.dataListLoading = false;
      });
    },
    sizeChangeHandle(val) { this.pageSize = val; this.pageIndex = 1; this.getDataList(); },
    currentChangeHandle(val) { this.pageIndex = val; this.getDataList(); },
    viewDetail(row) { this.currentRoom = row; this.detailVisible = true; },
    cleanRoom(row) {
      this.$confirm('????? ' + row.kefanghao + ' ????????', "????", { confirmButtonText: "????", cancelButtonText: "??", type: "warning" }).then(() => {
        this.$http({ url: 'daiqingsao/clean/' + row.id, method: "post" }).then(({ data }) => {
          if (data && data.code === 0) {
            this.$message({ message: data.msg || "????", type: "success", duration: 1500, onClose: () => { this.detailVisible = false; this.getDataList(); } });
          } else { this.$message.error(data.msg || "????"); }
        });
      }).catch(() => {});
    }
  }
};
</script>
<style lang="scss" scoped>
.slt { margin: 0 !important; display: flex; }
.ad { margin: 0 !important; display: flex; }
.tables {
  &::v-deep .el-button--success { background-color: #67c23a; border-color: #67c23a; color: #fff; }
  &::v-deep .el-button--info { background-color: #909399; border-color: #909399; color: #fff; }
  &::v-deep .el-button { margin: 4px; }
}
</style>
