<template>
  <div class="main-content">
    <!-- ??? -->
    <div v-if="showFlag">
      <el-form :inline="true" :model="searchForm" class="form-content">
        <el-row :gutter="20" class="slt">
          <el-form-item label="???">
            <el-input prefix-icon="el-icon-search" v-model="searchForm.kefanghao" placeholder="???" clearable></el-input>
          </el-form-item>
          <el-form-item label="??">
            <el-input prefix-icon="el-icon-search" v-model="searchForm.xingming" placeholder="??" clearable></el-input>
          </el-form-item>
          <el-form-item>
            <el-button icon="el-icon-search" type="success" @click="search()">??</el-button>
          </el-form-item>
        </el-row>
        <el-row class="ad">
          <el-form-item>
            <el-button v-if="isAuth('huiyuantuifang','??')" type="success" icon="el-icon-plus" @click="addOrUpdateHandler()">??</el-button>
            <el-button v-if="isAuth('huiyuantuifang','??')" :disabled="dataListSelections.length <= 0" type="danger" icon="el-icon-delete" @click="deleteHandler()">????</el-button>
          </el-form-item>
        </el-row>
      </el-form>
      <div class="table-content">
        <el-table class="tables" size="medium" border stripe v-if="isAuth('huiyuantuifang','??')" :data="dataList" v-loading="dataListLoading" @selection-change="selectionChangeHandler">
          <el-table-column type="selection" header-align="center" align="center" width="50"></el-table-column>
          <el-table-column label="??" type="index" width="50" align="center"></el-table-column>
          <el-table-column prop="dingdanbianhao" header-align="center" align="center" label="????"></el-table-column>
          <el-table-column prop="kefanghao" header-align="center" align="center" label="???"></el-table-column>
          <el-table-column prop="kefangleixing" header-align="center" align="center" label="????"></el-table-column>
          <el-table-column prop="suoshujiudian" header-align="center" align="center" label="????"></el-table-column>
          <el-table-column prop="zhanghao" header-align="center" align="center" label="??"></el-table-column>
          <el-table-column prop="xingming" header-align="center" align="center" label="??"></el-table-column>
          <el-table-column prop="shenfenzheng" header-align="center" align="center" label="???"></el-table-column>
          <el-table-column prop="shouji" header-align="center" align="center" label="??"></el-table-column>
          <el-table-column prop="ruzhuyajin" header-align="center" align="center" label="????"></el-table-column>
          <el-table-column prop="tuifangshijian" header-align="center" align="center" label="????" width="160"></el-table-column>
          <el-table-column prop="ispay" header-align="center" align="center" label="????">
            <template slot-scope="scope">
              <span style="margin-right:10px">{{scope.row.ispay=='???'?'???':'???'}}</span>
              <el-button v-if="scope.row.ispay!='???' && isAuth('huiyuantuifang','??')" type="text" icon="el-icon-edit" size="small" @click="payHandler(scope.row)">??</el-button>
            </template>
          </el-table-column>
          <el-table-column header-align="center" align="center" label="??" width="300">
            <template slot-scope="scope">
              <el-button v-if="isAuth('huiyuantuifang','??')" type="success" icon="el-icon-tickets" size="mini" @click="addOrUpdateHandler(scope.row.id,'info')">??</el-button>
              <el-button v-if="isAuth('huiyuantuifang','????') && scope.row.ispay=='???'" type="warning" icon="el-icon-s-operation" size="mini" @click="qingsaofangjianCrossAddOrUpdateHandler(scope.row,'cross')">????</el-button>
              <el-button v-if="isAuth('huiyuantuifang','??')" type="primary" icon="el-icon-edit" size="mini" @click="addOrUpdateHandler(scope.row.id)">??</el-button>
              <el-button v-if="isAuth('huiyuantuifang','??')" type="danger" icon="el-icon-delete" size="mini" @click="deleteHandler(scope.row.id)">??</el-button>
            </template>
          </el-table-column>
        </el-table>
        <el-pagination :layout="'total, sizes, prev, pager, next, jumper'" @size-change="sizeChangeHandle" @current-change="currentChangeHandle" :current-page="pageIndex" :page-sizes="[10, 20, 50, 100]" :page-size="pageSize" :total="totalPage" background style="text-align:right;margin-top:15px;"></el-pagination>
      </div>
    </div>
    <!-- ??/???? -->
    <add-or-update v-if="addOrUpdateFlag" :parent="this" ref="addOrUpdate"></add-or-update>
    <qingsaofangjian-cross-add-or-update v-if="qingsaofangjianCrossAddOrUpdateFlag" :parent="this" ref="qingsaofangjianCrossaddOrUpdate"></qingsaofangjian-cross-add-or-update>
  </div>
</template>
<script>
import AddOrUpdate from "./add-or-update";
import qingsaofangjianCrossAddOrUpdate from "../qingsaofangjian/add-or-update";
export default {
  data() {
    return {
      searchForm: { kefanghao: "", xingming: "" },
      dataList: [],
      pageIndex: 1,
      pageSize: 10,
      totalPage: 0,
      dataListLoading: false,
      dataListSelections: [],
      showFlag: true,
      addOrUpdateFlag: false,
      qingsaofangjianCrossAddOrUpdateFlag: false
    };
  },
  created() { this.getDataList(); },
  components: { AddOrUpdate, qingsaofangjianCrossAddOrUpdate },
  methods: {
    search() { this.pageIndex = 1; this.getDataList(); },
    getDataList() {
      this.dataListLoading = true;
      let params = { page: this.pageIndex, limit: this.pageSize, sort: 'id' };
      if (this.searchForm.kefanghao) params['kefanghao'] = '%' + this.searchForm.kefanghao + '%';
      if (this.searchForm.xingming) params['xingming'] = '%' + this.searchForm.xingming + '%';
      this.$http({ url: "huiyuantuifang/page", method: "get", params: params }).then(({ data }) => {
        if (data && data.code === 0) { this.dataList = data.data.list; this.totalPage = data.data.total; }
        else { this.dataList = []; this.totalPage = 0; }
        this.dataListLoading = false;
      });
    },
    sizeChangeHandle(val) { this.pageSize = val; this.pageIndex = 1; this.getDataList(); },
    currentChangeHandle(val) { this.pageIndex = val; this.getDataList(); },
    selectionChangeHandler(val) { this.dataListSelections = val; },
    addOrUpdateHandler(id, type) {
      this.showFlag = false;
      this.addOrUpdateFlag = true;
      this.qingsaofangjianCrossAddOrUpdateFlag = false;
      this.$nextTick(() => { this.$refs.addOrUpdate.init(id, type || 'else'); });
    },
    qingsaofangjianCrossAddOrUpdateHandler(row, type) {
      this.showFlag = false;
      this.addOrUpdateFlag = false;
      this.qingsaofangjianCrossAddOrUpdateFlag = true;
      this.$storage.set('crossObj', row);
      this.$storage.set('crossTable', 'huiyuantuifang');
      this.$nextTick(() => { this.$refs.qingsaofangjianCrossaddOrUpdate.init(row.id, type); });
    },
    payHandler(row) {
      this.$storage.set('paytable', 'huiyuantuifang');
      this.$storage.set('payObject', row);
      this.$router.push('pay');
    },
    deleteHandler(id) {
      var ids = id ? [Number(id)] : this.dataListSelections.map(item => Number(item.id));
      this.$confirm(`????[${id ? "??" : "????"}]???`, "??", { confirmButtonText: "??", cancelButtonText: "??", type: "warning" }).then(() => {
        this.$http({ url: "huiyuantuifang/delete", method: "post", data: ids }).then(({ data }) => {
          if (data && data.code === 0) { this.$message.success("????"); this.search(); }
          else { this.$message.error(data.msg); }
        });
      });
    }
  }
};
</script>
