<template>
  <div class="main-content">
    <div v-if="showFlag">
      <el-form :inline="true" :model="searchForm" class="form-content">
        <el-row :gutter="20" class="slt">
          <el-form-item label="???">
            <el-input prefix-icon="el-icon-search" v-model="searchForm.kefanghao" placeholder="???" clearable></el-input>
          </el-form-item>
          <el-form-item label="????">
            <el-select v-model="searchForm.fuwuleixing" placeholder="?????" clearable>
              <el-option v-for="item in typeOptions" :key="item" :label="item" :value="item"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item label="??">
            <el-select v-model="searchForm.zhuangtai" placeholder="?????" clearable>
              <el-option v-for="item in statusOptions" :key="item" :label="item" :value="item"></el-option>
            </el-select>
          </el-form-item>
          <el-form-item>
            <el-button icon="el-icon-search" type="success" @click="search()">??</el-button>
          </el-form-item>
        </el-row>
        <el-row class="ad">
          <el-form-item>
            <el-button v-if="isAuth('fuwujilu','??')" type="success" icon="el-icon-plus" @click="addOrUpdateHandler()">??</el-button>
            <el-button v-if="isAuth('fuwujilu','??')" :disabled="dataListSelections.length <= 0" type="danger" icon="el-icon-delete" @click="deleteHandler()">????</el-button>
          </el-form-item>
        </el-row>
      </el-form>
      <div class="table-content">
        <el-table class="tables" size="medium" border stripe :data="dataList" v-loading="dataListLoading" @selection-change="selectionChangeHandler">
          <el-table-column type="selection" header-align="center" align="center" width="50"></el-table-column>
          <el-table-column label="??" type="index" width="60" align="center"></el-table-column>
          <el-table-column prop="kefanghao" header-align="center" align="center" label="???"></el-table-column>
          <el-table-column prop="fuwuleixing" header-align="center" align="center" label="????">
            <template slot-scope="scope">
              <el-tag :type="getTypeTagType(scope.row.fuwuleixing)">{{scope.row.fuwuleixing}}</el-tag>
            </template>
          </el-table-column>
          <el-table-column prop="fuwuneirong" header-align="center" align="center" label="????" show-overflow-tooltip></el-table-column>
          <el-table-column prop="zhuangtai" header-align="center" align="center" label="??">
            <template slot-scope="scope">
              <el-tag :type="getStatusTagType(scope.row.zhuangtai)">{{scope.row.zhuangtai}}</el-tag>
            </template>
          </el-table-column>
          <el-table-column prop="shenqingshijian" header-align="center" align="center" label="????" width="160"></el-table-column>
          <el-table-column prop="wanchengshijian" header-align="center" align="center" label="????" width="160"></el-table-column>
          <el-table-column prop="beizhu" header-align="center" align="center" label="??" show-overflow-tooltip></el-table-column>
          <el-table-column header-align="center" align="center" label="??" width="200">
            <template slot-scope="scope">
              <el-button v-if="isAuth('fuwujilu','??')" type="success" icon="el-icon-tickets" size="mini" @click="addOrUpdateHandler(scope.row.id,'info')">??</el-button>
              <el-button v-if="isAuth('fuwujilu','??')" type="primary" icon="el-icon-edit" size="mini" @click="addOrUpdateHandler(scope.row.id)">??</el-button>
              <el-button v-if="isAuth('fuwujilu','??') && scope.row.zhuangtai=='???'" type="warning" icon="el-icon-s-operation" size="mini" @click="handleService(scope.row)">??</el-button>
              <el-button v-if="isAuth('fuwujilu','??')" type="danger" icon="el-icon-delete" size="mini" @click="deleteHandler(scope.row.id)">??</el-button>
            </template>
          </el-table-column>
        </el-table>
        <el-pagination :layout="'total, sizes, prev, pager, next, jumper'" @size-change="sizeChangeHandle" @current-change="currentChangeHandle" :current-page="pageIndex" :page-sizes="[10, 20, 50, 100]" :page-size="pageSize" :total="totalPage" background style="text-align:right;margin-top:15px;"></el-pagination>
      </div>
    </div>
    <add-or-update v-if="addOrUpdateFlag" :parent="this" ref="addOrUpdate"></add-or-update>
  </div>
</template>
<script>
import AddOrUpdate from "./add-or-update";
export default {
  data() {
    return {
      searchForm: { kefanghao: "", fuwuleixing: "", zhuangtai: "" },
      dataList: [],
      pageIndex: 1,
      pageSize: 10,
      totalPage: 0,
      dataListLoading: false,
      dataListSelections: [],
      showFlag: true,
      addOrUpdateFlag: false,
      typeOptions: ['????', '????', '????', '????', '????', '????', '????', '??'],
      statusOptions: ['???', '???', '???', '???']
    };
  },
  created() { this.getDataList(); },
  components: { AddOrUpdate },
  methods: {
    getTypeTagType(type) {
      const map = { '????': 'primary', '????': 'success', '????': 'info', '????': 'warning', '????': 'danger' };
      return map[type] || '';
    },
    getStatusTagType(status) {
      const map = { '???': 'warning', '???': 'primary', '???': 'success', '???': 'info' };
      return map[status] || '';
    },
    search() { this.pageIndex = 1; this.getDataList(); },
    getDataList() {
      this.dataListLoading = true;
      let params = { page: this.pageIndex, limit: this.pageSize, sort: 'id' };
      if(this.searchForm.kefanghao) params['kefanghao'] = '%' + this.searchForm.kefanghao + '%';
      if(this.searchForm.fuwuleixing) params['fuwuleixing'] = this.searchForm.fuwuleixing;
      if(this.searchForm.zhuangtai) params['zhuangtai'] = this.searchForm.zhuangtai;
      this.$http({ url: "fuwujilu/page", method: "get", params: params }).then(({ data }) => {
        if (data && data.code === 0) { this.dataList = data.data.list; this.totalPage = data.data.total; }
        else { this.dataList = []; this.totalPage = 0; }
        this.dataListLoading = false;
      });
    },
    sizeChangeHandle(val) { this.pageSize = val; this.pageIndex = 1; this.getDataList(); },
    currentChangeHandle(val) { this.pageIndex = val; this.getDataList(); },
    selectionChangeHandler(val) { this.dataListSelections = val; },
    addOrUpdateHandler(id, type) {
      this.showFlag = false;
      this.addOrUpdateFlag = true;
      this.$nextTick(() => { this.$refs.addOrUpdate.init(id, type || 'else'); });
    },
    handleService(row) {
      this.$confirm('??????????"???"?', '??', { confirmButtonText: '??', cancelButtonText: '??', type: 'warning' }).then(() => {
        this.$http({ url: `fuwujilu/update`, method: "post", data: { id: row.id, zhuangtai: '???' } }).then(({ data }) => {
          if (data && data.code === 0) { this.$message.success('????'); this.getDataList(); }
          else { this.$message.error(data.msg); }
        });
      }).catch(() => {});
    },
    deleteHandler(id) {
      var ids = id ? [Number(id)] : this.dataListSelections.map(item => Number(item.id));
      this.$confirm(`????[${id ? "??" : "????"}]???`, "??", { confirmButtonText: "??", cancelButtonText: "??", type: "warning" }).then(() => {
        this.$http({ url: "fuwujilu/delete", method: "post", data: ids }).then(({ data }) => {
          if (data && data.code === 0) { this.$message.success("????"); this.search(); }
          else { this.$message.error(data.msg); }
        });
      });
    }
  }
};
</script>
<style lang="scss" scoped>
.slt { margin: 0 !important; display: flex; }
.ad { margin: 0 !important; display: flex; }
.tables {
  &::v-deep .el-button--success { background-color: rgba(36, 194, 205, 1); border-color: rgba(36, 194, 205, 1); }
  &::v-deep .el-button--primary { background-color: rgba(102, 102, 153, 1); border-color: rgba(102, 102, 153, 1); }
  &::v-deep .el-button { margin: 4px; }
}
</style>
